import{_ as t,c as e,o as a,a2 as o}from"./chunks/framework.DdOM6S6U.js";const g=JSON.parse('{"title":"Custom Auth Pages","description":"","frontmatter":{"sidebarPos":1,"sidebarTitle":"Custom Auth Pages"},"headers":[],"relativePath":"guide/custom-auth-pages/index.md","filePath":"guide/custom-auth-pages/index.md","lastUpdated":null}'),i={name:"guide/custom-auth-pages/index.md"},s=o('<h1 id="custom-auth-pages" tabindex="-1">Custom Auth Pages <a class="header-anchor" href="#custom-auth-pages" aria-label="Permalink to &quot;Custom Auth Pages&quot;">​</a></h1><p>Modularity provides a flexible authentication system that you can fully customize without modifying package code. All auth pages (login, register, forgot password, etc.) are driven by configuration files.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><ul><li><strong>Package Auth (UeAuth)</strong>: Minimal, slot-based default component. No banner or app-specific content.</li><li><strong>Custom Auth (UeCustomAuth)</strong>: Your app-specific design. Add banner text, redirect buttons, split layouts, and any custom props.</li><li><strong>Attribute flow</strong>: All attributes from config are passed to the auth component via <code>v-bind</code>. Custom components receive whatever you define.</li></ul><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h2><ol><li>Create <code>modularity/auth_pages.php</code> in your app (or merge into <code>config/modularity.php</code>).</li><li>Add <code>attributes</code> for banner content, redirect buttons, etc.</li><li>Optionally use a custom auth component: publish <code>Auth.vue</code> and set <code>component_name</code> to <code>ue-custom-auth</code>.</li></ol><h2 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h2><ul><li><a href="./overview">Overview &amp; Architecture</a> — Package vs custom auth, attribute flow</li><li><a href="./configuration">Configuration</a> — auth_pages and auth_component config structure</li><li><a href="./attributes">Attributes &amp; Custom Props</a> — Passing custom attributes to auth components</li><li><a href="./custom-auth-component">Custom Auth Component</a> — Creating and using a custom Auth.vue</li><li><a href="./layout-presets">Layout Presets</a> — banner, minimal, and structural options</li><li><a href="./page-definitions">Page Definitions</a> — Per-page overrides (formDraft, formSlotsPreset, etc.)</li></ul>',8),r=[s];function n(u,c,l,d,h,m){return a(),e("div",null,r)}const f=t(i,[["render",n]]);export{g as __pageData,f as default};
